 25→const val REFRESH_DELAY = 500L
 26→
 27→class BloggingPromptCardSource @Inject constructor(
 28→    private val selectedSiteRepository: SelectedSiteRepository,
 29→    private val promptsStore: BloggingPromptsStore,
 30→    private val bloggingPromptsFeature: BloggingPromptsFeature,
 31→    private val bloggingPromptsSettingsHelper: BloggingPromptsSettingsHelper,
 32→    @param:Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher
 33→) : MySiteRefreshSource<BloggingPromptUpdate> {
 34→    override val refresh = MutableLiveData(false)
 35→    val singleRefresh = MutableLiveData(false)
 36→
 37→    companion object {
 38→        private const val NUM_PROMPTS_TO_REQUEST = 20
 39→    }
 40→
 41→    override fun build(coroutineScope: CoroutineScope, siteLocalId: Int): LiveData<BloggingPromptUpdate> {
 42→        val result = MediatorLiveData<BloggingPromptUpdate>()
 43→        result.getData(coroutineScope, siteLocalId)
 44→        result.addSource(refresh) { result.refreshData(coroutineScope, siteLocalId, refresh.value) }
 45→        result.addSource(singleRefresh) { result.refreshData(coroutineScope, siteLocalId, singleRefresh.value, true) }
 46→        refresh()
 47→        return result
 48→    }
 49→
 50→    fun refreshTodayPrompt() {
 51→        if (isRefreshing() == false) {
 52→            singleRefresh.postValue(true)
 53→        }
 54→    }
 55→
 56→    private fun MediatorLiveData<BloggingPromptUpdate>.getData(
 57→        coroutineScope: CoroutineScope,
 58→        siteLocalId: Int
 59→    ) {
 60→        val selectedSite = selectedSiteRepository.getSelectedSite()
 61→        if (selectedSite != null && selectedSite.id == siteLocalId && bloggingPromptsFeature.isEnabled()) {
 62→            coroutineScope.launch(bgDispatcher) {
 63→                if (bloggingPromptsSettingsHelper.shouldShowPromptsFeature()) {
 64→                    promptsStore.getPrompts(selectedSite)
 65→                        .map { it.model?.filter { prompt -> isSameDay(prompt.date, Date()) } }
 66→                        .collect { result ->
 67→                            postValue(BloggingPromptUpdate(result?.firstOrNull()))
 68→                        }
 69→                } else {
 70→                    postEmptyState()
 71→                }
 72→            }
 73→        } else {
 74→            postLastState()
 75→        }
 76→    }
 77→
 78→    private fun MediatorLiveData<BloggingPromptUpdate>.refreshData(
 79→        coroutineScope: CoroutineScope,
 80→        siteLocalId: Int,
 81→        isRefresh: Boolean? = null,
 82→        isSinglePromptRefresh: Boolean = false
 83→    ) {
 84→        when (isRefresh) {
 85→            null, true -> refreshData(coroutineScope, siteLocalId, isSinglePromptRefresh)
 86→            else -> Unit // Do nothing
 87→        }
 88→    }
 89→
 90→    private fun MediatorLiveData<BloggingPromptUpdate>.refreshData(
 91→        coroutineScope: CoroutineScope,
 92→        siteLocalId: Int,
 93→        isSinglePromptRefresh: Boolean = false
 94→    ) {
 95→        val selectedSite = selectedSiteRepository.getSelectedSite()
 96→        if (selectedSite != null && selectedSite.id == siteLocalId) {
 97→            if (bloggingPromptsFeature.isEnabled()) {
 98→                coroutineScope.launch(bgDispatcher) {
 99→                    if (bloggingPromptsSettingsHelper.shouldShowPromptsFeature()) {
100→                        fetchPromptsAndPostErrorIfAvailable(coroutineScope, selectedSite, isSinglePromptRefresh)
101→                    } else {
102→                        postEmptyState()
103→                    }
104→                }
105→            } else {
106→                postEmptyState()
107→            }
108→        } else {
109→            postLastState()
110→        }
111→    }
112→
113→    private fun MediatorLiveData<BloggingPromptUpdate>.fetchPromptsAndPostErrorIfAvailable(
114→        coroutineScope: CoroutineScope,
115→        selectedSite: SiteModel,
116→        isSinglePromptRefresh: Boolean = false
117→    ) {
118→        coroutineScope.launch(bgDispatcher) {
119→            delay(REFRESH_DELAY)
120→            val numOfPromptsToFetch = if (isSinglePromptRefresh) 1 else NUM_PROMPTS_TO_REQUEST
121→            val result = promptsStore.fetchPrompts(selectedSite, numOfPromptsToFetch, Date())
122→            when {
123→                result.isError -> postLastState()
124→                else -> {
125→                    result.model
126→                        ?.firstOrNull { prompt -> isSameDay(prompt.date, Date()) }
127→                        ?.let { prompt -> postState(BloggingPromptUpdate(prompt)) }
128→                        ?: postLastState()
129→                }
130→            }
131→        }
132→    }
133→
134→    /**
135→     * This function is used to make sure the [refresh] information is propagated and processed correctly even though
136→     * the previous status is still the current one. This avoids issues like the loading progress indicator being shown
137→     * indefinitely.
138→     *
139→     * Also, for this card source, this can be used as the error state as we don't have any special error handling at
140→     * this point, so we just show the last available prompt.
141→     */
142→    private fun MediatorLiveData<BloggingPromptUpdate>.postLastState() {
143→        val lastPrompt = this.value?.promptModel
144→        postState(BloggingPromptUpdate(lastPrompt))
145→    }
146→
147→    private fun MediatorLiveData<BloggingPromptUpdate>.postEmptyState() {
148→        postState(BloggingPromptUpdate(null))
149→    }
150→
151→    private fun isSameDay(date1: Date, date2: Date): Boolean {
152→        val localDate1: LocalDate = date1.toInstant()
153→            .atZone(ZoneId.systemDefault())
154→            .toLocalDate()
155→        val localDate2: LocalDate = date2.toInstant()
156→            .atZone(ZoneId.systemDefault())
157→            .toLocalDate()
158→        return localDate1.isEqual(localDate2)
159→    }
160→}
